// src/services/lastfm-client.ts
var LASTFM_API_BASE_URL = "https://ws.audioscrobbler.com/2.0/";

class LastFmError extends Error {
  code;
  statusCode;
  constructor(message, code, statusCode) {
    super(message);
    this.code = code;
    this.statusCode = statusCode;
    this.name = "LastFmError";
  }
}
async function makeLastFmRequest(params) {
  const apiKey = globalThis.LASTFM_API_KEY;
  if (!apiKey) {
    throw new LastFmError("Last.fm API key not configured", undefined, 500);
  }
  const url = new URL(LASTFM_API_BASE_URL);
  url.searchParams.set("api_key", apiKey);
  url.searchParams.set("format", "json");
  for (const [key, value] of Object.entries(params)) {
    url.searchParams.set(key, value);
  }
  try {
    const response = await fetch(url.toString(), {
      method: "GET",
      headers: {
        "User-Agent": "lastfm-mcp-server/1.0.0"
      }
    });
    if (!response.ok) {
      if (response.status === 429) {
        throw new LastFmError("Rate limit exceeded. Please try again later.", 29, 429);
      }
      throw new LastFmError(`HTTP error ${response.status}: ${response.statusText}`, undefined, response.status);
    }
    const data = await response.json();
    if (data && typeof data === "object" && "error" in data) {
      const errorMessages2 = {
        2: "Invalid service - This service does not exist",
        3: "Invalid Method - No method with that name",
        4: "Authentication Failed - Invalid authentication token",
        5: "Invalid format - This service doesn't exist in that format",
        6: "Invalid parameters - Required parameter is missing",
        7: "Invalid resource specified",
        8: "Operation failed - Something went wrong",
        9: "Invalid session key - Please re-authenticate",
        10: "Invalid API key - You must use a valid API key",
        11: "Service Offline - This service is temporarily offline",
        13: "Invalid method signature supplied",
        16: "Temporarily unavailable - Service is temporarily unavailable",
        26: "Suspended API key - Access for your account has been suspended",
        29: "Rate limit exceeded - Your IP has made too many requests"
      };
      const errorMessage = errorMessages2[data.error] || data.message || "Unknown error";
      throw new LastFmError(errorMessage, data.error);
    }
    return data;
  } catch (error) {
    if (error instanceof LastFmError) {
      throw error;
    }
    throw new LastFmError(`Failed to fetch from Last.fm API: ${error.message}`);
  }
}
function formatMarkdownList(items, formatter) {
  return items.map((item, index) => `${index + 1}. ${formatter(item)}`).join(`

`);
}
function formatJsonResponse(data) {
  return {
    success: true,
    data,
    timestamp: new Date().toISOString()
  };
}

