var ResponseFormat;
((ResponseFormat2) => {
  ResponseFormat2["MARKDOWN"] = "markdown";
  ResponseFormat2["JSON"] = "json";
})(ResponseFormat ||= {});

// src/index.ts
var server = new McpServer({
  name: "lastfm-mcp-server",
  version: "1.0.0"
});
server.registerTool("lastfm_artist_search", {
  title: "Search for Artists",
  description: `Search for artists on Last.fm by name.

This tool searches the Last.fm database for artists matching the query string. Results are sorted by relevance and include listener counts.

Args:
  - query (string): Artist name or search query (required)
  - limit (number): Maximum results to return, 1-50 (default: 20)
  - response_format ('markdown' | 'json'): Output format (default: 'markdown')

Returns:
  For JSON format: { artists: [{ name, listeners, url, mbid }], total_results }
  For Markdown format: Formatted list of artists with listener counts

Examples:
  - Search for "Radiohead" вЖТ params with query="Radiohead"
  - Find artists similar to "Beatles" вЖТ query="Beatles"

Error Handling:
  - Returns "No artists found" if search returns empty
  - Returns error message if API request fails`,
  inputSchema: exports_external.object({
    query: exports_external.string().min(1, "Query cannot be empty").describe("Artist name or search query"),
    limit: exports_external.number().int().min(1).max(50).default(20).describe("Maximum number of results (1-50)"),
    response_format: exports_external.nativeEnum(ResponseFormat).default("markdown" /* MARKDOWN */).describe("Output format: 'markdown' or 'json'")
  }).strict(),
  annotations: {
    readOnlyHint: true,
    destructiveHint: false,
    idempotentHint: true,
    openWorldHint: true
  }
}, async (params) => {
  try {
    const data = await makeLastFmRequest({
      method: "artist.search",
      artist: params.query,
      limit: params.limit.toString()
    });
    if (!data.results?.artistmatches?.artist) {
      return {
        content: [{
          type: "text",
          text: `No artists found for "${params.query}"`
        }]
      };
    }
    const artists = Array.isArray(data.results.artistmatches.artist) ? data.results.artistmatches.artist : [data.results.artistmatches.artist];
    const totalResults = parseInt(data.results["opensearch:totalResults"] || "0");
    if (params.response_format === "json" /* JSON */) {
      const output = formatJsonResponse({
        artists: artists.map((a) => ({
          name: a.name,
          listeners: parseInt(a.listeners || "0"),
          url: a.url,
          mbid: a.mbid || null
        })),
        total_results: totalResults,
        limit: params.limit
      });
      return {
        content: [{ type: "text", text: JSON.stringify(output) }],
        structuredContent: output
      };
    }
    const markdown = formatMarkdownList(artists, (a) => `**${a.name}** - ${parseInt(a.listeners || "0").toLocaleString()} listeners
[Last.fm Profile](${a.url})`);
    return {
      content: [{
        type: "text",
        text: `# Artist Search Results for "${params.query}"

Found ${totalResults} total results (showing ${artists.length}):

${markdown}`
      }]
    };
  } catch (error) {
    return {
      isError: true,
      content: [{
        type: "text",
        text: error instanceof LastFmError ? error.message : `Error searching artists: ${error.message}`
      }]
    };
  }
});
server.registerTool("lastfm_artist_info", {
  title: "Get Artist Information",
  description: `Retrieve detailed information about an artist on Last.fm.

Returns comprehensive artist data including biography, statistics, similar artists, and tags.

Args:
  - artist (string): Artist name (required, unless mbid provided)
  - mbid (string): MusicBrainz ID (optional, overrides artist name)
  - username (string): Last.fm username for personalized playcount (optional)
  - response_format ('markdown' | 'json'): Output format (default: 'markdown')

Returns:
  Artist details including name, biography, listeners, playcount, similar artists, and top tags

Examples:
  - Get info about "Pink Floyd" вЖТ params with artist="Pink Floyd"
  - Get info with MusicBrainz ID вЖТ mbid="83d91898-7763-47d7-b03b-b92132375c47"`,
  inputSchema: exports_external.object({
    artist: exports_external.string().optional().describe("Artist name"),
    mbid: exports_external.string().optional().describe("MusicBrainz ID (MBID) for the artist"),
    username: exports_external.string().optional().describe("Last.fm username for personalized data"),
    response_format: exports_external.nativeEnum(ResponseFormat).default("markdown" /* MARKDOWN */).describe("Output format")
  }).strict().refine((data) => data.artist || data.mbid, {
    message: "Either 'artist' or 'mbid' must be provided"
  }),
  annotations: {
    readOnlyHint: true,
    destructiveHint: false,
    idempotentHint: true,
    openWorldHint: true
  }
}, async (params) => {
  try {
    const requestParams = {
      method: "artist.getinfo"
    };
    if (params.artist)
      requestParams.artist = params.artist;
    if (params.mbid)
      requestParams.mbid = params.mbid;
    if (params.username)
      requestParams.username = params.username;
    const data = await makeLastFmRequest(requestParams);
    const artist = data.artist;
    if (!artist) {
      return {
        content: [{
          type: "text",
          text: "Artist not found"
        }]
      };
    }
    if (params.response_format === "json" /* JSON */) {
      const output = formatJsonResponse({
        name: artist.name,
        mbid: artist.mbid || null,
        url: artist.url,
        listeners: parseInt(artist.stats?.listeners || "0"),
        playcount: parseInt(artist.stats?.playcount || "0"),
        user_playcount: artist.stats?.userplaycount ? parseInt(artist.stats.userplaycount) : null,
        biography: artist.bio?.summary || null,
        similar_artists: artist.similar?.artist?.slice(0, 5).map((a) => ({
          name: a.name,
          url: a.url
        })) || [],
        tags: artist.tags?.tag?.slice(0, 5).map((t) => t.name) || []
      });
      return {
        content: [{ type: "text", text: JSON.stringify(output) }],
        structuredContent: output
      };
    }
    let markdown = `# ${artist.name}

`;
    markdown += `**Listeners:** ${parseInt(artist.stats?.listeners || "0").toLocaleString()}
`;
    markdown += `**Total Plays:** ${parseInt(artist.stats?.playcount || "0").toLocaleString()}
`;
    if (artist.stats?.userplaycount) {
      markdown += `**Your Plays:** ${parseInt(artist.stats.userplaycount).toLocaleString()}
`;
    }
    markdown += `
[Last.fm Profile](${artist.url})
`;
    if (artist.bio?.summary) {
      markdown += `
## Biography
${artist.bio.summary.replace(/<a href[^>]*>Read more.*?<\/a>/gi, "").trim()}
`;
    }
    if (artist.similar?.artist && artist.similar.artist.length > 0) {
      markdown += `
## Similar Artists
`;
      artist.similar.artist.slice(0, 5).forEach((a) => {
        markdown += `- [${a.name}](${a.url})
`;
      });
    }
    if (artist.tags?.tag && artist.tags.tag.length > 0) {
      markdown += `
## Tags
`;
      markdown += artist.tags.tag.slice(0, 5).map((t) => t.name).join(", ");
    }
    return {
      content: [{ type: "text", text: markdown }]
    };
  } catch (error) {
    return {
      isError: true,
      content: [{
        type: "text",
        text: error instanceof LastFmError ? error.message : `Error fetching artist info: ${error.message}`
      }]
    };
  }
});
