server.registerTool("lastfm_track_info", {
  title: "Get Track Information",
  description: `Get detailed information about a track on Last.fm.

Args:
  - artist (string): Artist name (required, unless mbid provided)
  - track (string): Track name (required, unless mbid provided)
  - mbid (string): MusicBrainz ID (optional)
  - username (string): Last.fm username for personalized data (optional)
  - response_format ('markdown' | 'json'): Output format (default: 'markdown')

Returns:
  Track details including artist, album, duration, playcount, listeners, and tags`,
  inputSchema: exports_external.object({
    artist: exports_external.string().optional().describe("Artist name"),
    track: exports_external.string().optional().describe("Track name"),
    mbid: exports_external.string().optional().describe("MusicBrainz ID"),
    username: exports_external.string().optional().describe("Last.fm username"),
    response_format: exports_external.nativeEnum(ResponseFormat).default("markdown" /* MARKDOWN */).describe("Output format")
  }).strict().refine((data) => data.artist && data.track || data.mbid, {
    message: "Either ('artist' and 'track') or 'mbid' must be provided"
  }),
  annotations: {
    readOnlyHint: true,
    destructiveHint: false,
    idempotentHint: true,
    openWorldHint: true
  }
}, async (params) => {
  try {
    const requestParams = {
      method: "track.getinfo"
    };
    if (params.artist)
      requestParams.artist = params.artist;
    if (params.track)
      requestParams.track = params.track;
    if (params.mbid)
      requestParams.mbid = params.mbid;
    if (params.username)
      requestParams.username = params.username;
    const data = await makeLastFmRequest(requestParams);
    const track = data.track;
    if (!track) {
      return {
        content: [{
          type: "text",
          text: "Track not found"
        }]
      };
    }
    if (params.response_format === "json" /* JSON */) {
      const output = formatJsonResponse({
        name: track.name,
        artist: track.artist?.name || null,
        album: track.album?.title || null,
        duration: parseInt(track.duration || "0"),
        listeners: parseInt(track.listeners || "0"),
        playcount: parseInt(track.playcount || "0"),
        user_playcount: track.userplaycount ? parseInt(track.userplaycount) : null,
        user_loved: track.userloved === "1",
        url: track.url,
        tags: track.toptags?.tag?.slice(0, 5).map((t) => t.name) || []
      });
      return {
        content: [{ type: "text", text: JSON.stringify(output) }],
        structuredContent: output
      };
    }
    let markdown = `# ${track.name}
by **${track.artist?.name}**

`;
    if (track.album?.title) {
      markdown += `**Album:** ${track.album.title}
`;
    }
    if (track.duration && parseInt(track.duration) > 0) {
      const minutes = Math.floor(parseInt(track.duration) / 60000);
      const seconds = Math.floor(parseInt(track.duration) % 60000 / 1000);
      markdown += `**Duration:** ${minutes}:${seconds.toString().padStart(2, "0")}
`;
    }
    markdown += `**Listeners:** ${parseInt(track.listeners || "0").toLocaleString()}
`;
    markdown += `**Total Plays:** ${parseInt(track.playcount || "0").toLocaleString()}
`;
    if (track.userplaycount) {
      markdown += `**Your Plays:** ${parseInt(track.userplaycount).toLocaleString()}
`;
    }
    if (track.userloved === "1") {
      markdown += `вЭ§пЄП **You love this track**
`;
    }
    markdown += `
[Last.fm Profile](${track.url})
`;
    if (track.toptags?.tag && track.toptags.tag.length > 0) {
      markdown += `
## Tags
`;
      markdown += track.toptags.tag.slice(0, 5).map((t) => t.name).join(", ");
    }
    return {
      content: [{ type: "text", text: markdown }]
    };
  } catch (error) {
    return {
      isError: true,
      content: [{
        type: "text",
        text: error instanceof LastFmError ? error.message : `Error fetching track info: ${error.message}`
      }]
    };
  }
});
